const body = $input.first().json.body ?? $input.first().json;
    const cvText = body.extracted_cv_text ?? '';
    const fullName = body.full_name ?? '';
    const email = body.email ?? '';

    if (!cvText || cvText.trim() === '') {
      throw new Error('extracted_cv_text is empty or missing');
    }

    return [{ json: { cv_text: cvText, full_name: fullName, email: email } }];

const raw = $input.first().json.response
            ?? $input.first().json.text
            ?? $input.first().json.message?.content
            ?? '';

let parsed;
try {
  const clean = raw.replace(/```json/g, '').replace(/```/g, '').trim();
  parsed = JSON.parse(clean);
} catch(e) {
  throw new Error('CV Parser — Ollama returned invalid JSON: ' + raw.substring(0, 300));
}

// Soft skills only — no hard_skills field
parsed.soft_skills_hints = Array.isArray(parsed.soft_skills_hints)
  ? parsed.soft_skills_hints
  : [];
parsed.experience_years  = parsed.experience_years ?? 0;
parsed.education_level   = parsed.education_level  ?? 'other';
parsed.cv_score          = parsed.cv_score          ?? 0;

return [{ json: parsed }];
